import { generateText } from 'ai';
import { vexMiddleware } from '@vex_dev/sdk/ai/vercel';

const vex = vexMiddleware({
  orgId: 'edu_org_123',
  rules: ['no-pii', 'ferpa-student-data', 'age-appropriate'],
});

export async function generateLesson(studentPrompt: string, studentId: string) {
  const { text } = await generateText({
    model: 'gpt-4o',
    prompt: studentPrompt,
    middleware: [vex],
    metadata: { studentId, context: 'tutoring' },
  });
  return text;
}

import { streamText } from 'ai';
import { vexMiddleware } from '@vex_dev/sdk/ai/vercel';

const safetyVex = vexMiddleware({
  orgId: 'edu_org_123',
  rules: ['no-hallucinations', 'coppa-safe', 'bias-detection'],
  stream: true,
});

export async function streamTutorResponse(query: string) {
  const result = await streamText({
    model: 'gpt-4o-mini',
    prompt: `Tutor response to: ${query}`,
    middleware: [safetyVex],
  });

  return result.toReadableStream();
}

